import { test, expect } from '@playwright/test';

// Helpers
function captureEdgeFunctionRequests(page) {
  const calls: any[] = [];
  let routeInstalled = false;
  return {
    calls,
    async install(routeOnce = false) {
      if (routeInstalled) return;
      routeInstalled = true;
      await page.route('**/functions/v1/get-meal-suggestions', async (route) => {
        const req = route.request();
        const body = (() => {
          try {
            return req.postDataJSON();
          } catch {
            return {};
          }
        })();
        calls.push(body);

        // Fulfill based on whether filters are present
        const isFiltered = body && body.filters && (body.filters.dietaryTypes?.length || body.filters.mealTypes?.length);
        if (!isFiltered) {
          await route.fulfill({
            status: 200,
            contentType: 'application/json',
            body: JSON.stringify([
              { id: '10', name: 'Spaghetti Bolognese', image_url: '' },
              { id: '11', name: 'Chicken Curry', image_url: '' },
            ]),
          });
          return;
        }

        // Basic filtered suggestions (Edge Function filtered response shape)
        const startDate = body.startDate || '2025-01-01';
        const mealTypes = body.filters?.mealTypes?.length ? body.filters.mealTypes : ['dinner'];
        const suggestions = mealTypes.map((mt, i) => ({
          date: startDate,
          mealType: mt,
          meal: {
            id: `${100 + i}`,
            name: body.filters?.dietaryTypes?.includes('vegetarian')
              ? `Veg Option ${i + 1}`
              : `Meal Option ${i + 1}`,
            image_url: '',
            tags: body.filters?.dietaryTypes ?? [],
            last_prepared: null,
          },
          reason: 'Matches filters',
        }));

        await route.fulfill({
          status: 200,
          contentType: 'application/json',
          body: JSON.stringify(suggestions),
        });
        if (routeOnce) await page.unroute('**/functions/v1/get-meal-suggestions');
      });
    },
  };
}

// NOTE: Tests rely on globalSetup auth and .env as configured in playwright.config.ts
// Base URL is http://localhost:3001 per config.

test.describe('Plan page filtering (E2E)', () => {
  test('applies dietary filter, updates URL, and includes filters in Edge request', async ({ page }) => {
    const ef = captureEdgeFunctionRequests(page);
    await ef.install();

    await page.goto('/plan');
    await expect(page.getByRole('heading', { name: 'Meal Suggestions' })).toBeVisible();

    // Click vegetarian filter
    await page.getByRole('button', { name: 'vegetarian' }).click();

    // URL should include dietary
    await expect(page).toHaveURL(/dietary=vegetarian/);

    // A filtered request should be made including dietaryTypes
    await expect.poll(() => {
      const match = ef.calls.find((b) => Array.isArray(b?.filters?.dietaryTypes) && b.filters.dietaryTypes.includes('vegetarian'));
      return !!match;
    }, { timeout: 10_000 }).toBe(true);

    // Clear Filters button visible now
    await expect(page.getByRole('button', { name: 'Clear filters' })).toBeVisible();
  });

  test('applies meal type filter, updates URL, and includes mealTypes in Edge request', async ({ page }) => {
    const ef = captureEdgeFunctionRequests(page);
    await ef.install();

    await page.goto('/plan');
    await expect(page.getByRole('heading', { name: 'Meal Suggestions' })).toBeVisible();

    // Select Lunch
    await page.getByRole('button', { name: 'Lunch' }).click();

    // URL should include meals=lunch
    await expect(page).toHaveURL(/meals=lunch/);

    // Edge request should include mealTypes ["lunch"]
    await expect.poll(() => {
      const match = ef.calls.find((b) => Array.isArray(b?.filters?.mealTypes) && b.filters.mealTypes.length === 1 && b.filters.mealTypes[0] === 'lunch');
      return !!match;
    }, { timeout: 10_000 }).toBe(true);
  });

  test('clear filters resets URL and triggers unfiltered Edge request', async ({ page }) => {
    const ef = captureEdgeFunctionRequests(page);
    await ef.install();

    await page.goto('/plan?dietary=vegan&meals=breakfast');
    await expect(page.getByRole('heading', { name: 'Meal Suggestions' })).toBeVisible();

    // Ensure a filtered call happened first
    await expect.poll(() => ef.calls.some((b) => b?.filters)).toBeTruthy();

    // Clear filters
    await page.getByRole('button', { name: 'Clear filters' }).click();

    // URL should be clean (no dietary or meals params)
    await expect(page).not.toHaveURL(/(dietary=|meals=)/);

    // An unfiltered call should be made (empty body or no filters)
    await expect.poll(() => {
      const last = ef.calls[ef.calls.length - 1];
      const isUnfiltered = last && (!last.filters || (Array.isArray(last.filters?.mealTypes) && last.filters.mealTypes.length === 3));
      // We treat both legacy {} and explicit all-types as acceptable
      return isUnfiltered;
    }, { timeout: 10_000 }).toBe(true);

    // Clear button disappears
    await expect(page.getByRole('button', { name: 'Clear filters' })).toBeHidden();
  });

  test('restores filters from URL on initial load', async ({ page }) => {
    const ef = captureEdgeFunctionRequests(page);
    await ef.install();

    await page.goto('/plan?dietary=vegetarian,gluten-free&meals=lunch');

    // Expect a filtered call with both dietaryTypes and mealTypes
    await expect.poll(() => {
      const match = ef.calls.find((b) => {
        const d = b?.filters?.dietaryTypes || [];
        const m = b?.filters?.mealTypes || [];
        return Array.isArray(d) && d.includes('vegetarian') && d.includes('gluten-free') && Array.isArray(m) && m.length === 1 && m[0] === 'lunch';
      });
      return !!match;
    }, { timeout: 10_000 }).toBe(true);

    // Clear Filters should be visible since filters are active
    await expect(page.getByRole('button', { name: 'Clear filters' })).toBeVisible();
  });
});

import { serve } from 'https://deno.land/std@0.177.0/http/server.ts';
import { corsHeaders } from '../_shared/cors.ts';
import 'jsr:@supabase/functions-js/edge-runtime.d.ts';
import { createClient, SupabaseClient } from 'https://esm.sh/@supabase/supabase-js@2';

interface FilterRequest {
  startDate?: string;  // ISO date string
  days?: number;       // Number of days to plan for
  filters?: {
    mealTypes?: string[];  // e.g., ["breakfast", "lunch", "dinner"]
    dietaryTypes?: string[]; // e.g., ["vegetarian", "gluten-free"]
  };
}

interface MealSuggestionResponse {
  date: string;       // ISO date string
  mealType: string;   // e.g., "breakfast", "lunch", "dinner"
  meal: {
    id: string;
    name: string;
    image_url?: string;
    tags: string[];
    last_prepared?: string | null;
  };
  reason?: string;    // Optional explanation for the suggestion
}

type LastPreparedMap = Record<number, string>;
type PreferenceScoreMap = Record<number, number>;

async function getSupabase(req: Request): Promise<SupabaseClient | null> {
  const url = Deno.env.get('SUPABASE_URL') || Deno.env.get('NEXT_PUBLIC_SUPABASE_URL') || '';
  const anon = Deno.env.get('SUPABASE_ANON_KEY') || Deno.env.get('NEXT_PUBLIC_SUPABASE_ANON_KEY') || '';
  if (!url || !anon) return null;
  const authHeader = req.headers.get('Authorization') ?? '';
  return createClient(url, anon, { global: { fetch }, headers: { Authorization: authHeader } });
}

async function fetchLastPreparedMap(supabase: SupabaseClient | null, mealIds: number[]): Promise<LastPreparedMap> {
  const map: LastPreparedMap = {};
  if (!supabase || mealIds.length === 0) return map;
  const { data, error } = await supabase
    .from('meal_history')
    .select('meal_id, action_date')
    .in('meal_id', mealIds)
    .order('action_date', { ascending: false });
  if (error) {
    console.error('Failed to fetch meal history:', error);
    return map;
  }
  for (const row of data as Array<{ meal_id: number; action_date: string }>) {
    if (map[row.meal_id] === undefined) {
      map[row.meal_id] = row.action_date;
    }
  }
  return map;
}

async function fetchPreferenceScoreMap(supabase: SupabaseClient | null, mealIds: number[], daysLookback = 90): Promise<PreferenceScoreMap> {
  const map: PreferenceScoreMap = {};
  if (!supabase || mealIds.length === 0) return map;
  const since = new Date();
  since.setDate(since.getDate() - daysLookback);
  const { data, error } = await supabase
    .from('meal_history')
    .select('meal_id, action_type, action_date')
    .in('meal_id', mealIds)
    .gte('action_date', since.toISOString());
  if (error) {
    console.error('Failed to fetch preference signals:', error);
    return map;
  }
  for (const row of data as Array<{ meal_id: number; action_type: string }>) {
    const weight =
      row.action_type === 'cooked' ? 2 :
      row.action_type === 'planned' ? 1 :
      row.action_type === 'skipped' ? -1 : 0;
    map[row.meal_id] = (map[row.meal_id] ?? 0) + weight;
  }
  return map;
}

serve(async (req) => {
  if (req.method === 'OPTIONS') {
    return new Response('ok', { headers: corsHeaders });
  }

  try {
    const requestBody: FilterRequest = await req.json().catch(() => ({}));

    // Check if this is a legacy request (empty body) or new filtered request
    const isLegacyRequest = Object.keys(requestBody).length === 0;

    if (isLegacyRequest) {
      // Return simple suggestions for backward compatibility
      // NOTE: `last_prepared` is included for UI hints; actual values to be populated via LRU logic.
      const suggestions = [
        { id: '1', name: 'Spaghetti Bolognese', image_url: '', last_prepared: null as string | null },
        { id: '2', name: 'Chicken Curry', image_url: '', last_prepared: null as string | null },
        { id: '3', name: 'Tofu Stir-Fry', image_url: '', last_prepared: null as string | null },
      ];

      // LRU prioritization using meal_history: compute last_prepared per meal and sort ascending (least recently used first).
      const supabase = await getSupabase(req);
      const ids = suggestions.map(s => Number(s.id)).filter((n) => Number.isFinite(n));
      const lastMap = await fetchLastPreparedMap(supabase, ids);
      const prefMap = await fetchPreferenceScoreMap(supabase, ids);
      const enriched = suggestions
        .map(s => ({
          ...s,
          last_prepared: lastMap[Number(s.id)] ?? null,
        }))
        .sort((a, b) => {
          const aKey = a.last_prepared ? new Date(a.last_prepared).getTime() : 0;
          const bKey = b.last_prepared ? new Date(b.last_prepared).getTime() : 0;
          if (aKey !== bKey) {
            return aKey - bKey; // least-recently-used first; never-used first
          }
          // Secondary: user preference score (higher is better)
          const aPref = prefMap[Number(a.id)] ?? 0;
          const bPref = prefMap[Number(b.id)] ?? 0;
          return bPref - aPref;
        });

      return new Response(JSON.stringify(enriched), {
        headers: { ...corsHeaders, 'Content-Type': 'application/json' },
        status: 200,
      });
    }

    // Handle filtered requests
    const startDate = requestBody.startDate || new Date().toISOString().split('T')[0];
    const days = requestBody.days || 7;
    const mealTypes = requestBody.filters?.mealTypes || ['breakfast', 'lunch', 'dinner'];
    const dietaryTypes = requestBody.filters?.dietaryTypes || [];

    // Mock meal database with dietary tags
    const mockMeals = [
      { id: '1', name: 'Spaghetti Bolognese', image_url: '', tags: ['pasta', 'italian'], last_prepared: null as string | null },
      { id: '2', name: 'Chicken Curry', image_url: '', tags: ['spicy', 'indian'], last_prepared: null as string | null },
      { id: '3', name: 'Tofu Stir-Fry', image_url: '', tags: ['vegetarian', 'asian', 'healthy'], last_prepared: null as string | null },
      { id: '4', name: 'Greek Salad', image_url: '', tags: ['vegetarian', 'mediterranean', 'healthy'], last_prepared: null as string | null },
      { id: '5', name: 'Gluten-Free Pancakes', image_url: '', tags: ['gluten-free', 'breakfast', 'sweet'], last_prepared: null as string | null },
      { id: '6', name: 'Quinoa Bowl', image_url: '', tags: ['vegetarian', 'gluten-free', 'healthy'], last_prepared: null as string | null },
      { id: '7', name: 'Beef Tacos', image_url: '', tags: ['mexican', 'spicy'], last_prepared: null as string | null },
      { id: '8', name: 'Salmon Teriyaki', image_url: '', tags: ['fish', 'japanese', 'healthy'], last_prepared: null as string | null },
    ];

    // Filter meals based on dietary restrictions
    const filteredMeals = mockMeals.filter(meal => {
      if (dietaryTypes.length === 0) return true;
      return dietaryTypes.some(dietType => meal.tags.includes(dietType));
    });

    if (filteredMeals.length === 0) {
      return new Response(JSON.stringify([]), {
        headers: { ...corsHeaders, 'Content-Type': 'application/json' },
        status: 200,
      });
    }

    // Generate suggestions for the requested date range and meal types
    const suggestions: MealSuggestionResponse[] = [];
    const start = new Date(startDate);

    // LRU prioritization: sort candidate meals by last_prepared ascending (null first)
    const supabase = await getSupabase(req);
    const candidateIds = filteredMeals.map(m => Number(m.id)).filter((n) => Number.isFinite(n));
    const lastMap = await fetchLastPreparedMap(supabase, candidateIds);
    const prefMap = await fetchPreferenceScoreMap(supabase, candidateIds);
    const sortedMeals = [...filteredMeals].sort((a, b) => {
      const aKey = lastMap[Number(a.id)] ? new Date(lastMap[Number(a.id)]).getTime() : 0;
      const bKey = lastMap[Number(b.id)] ? new Date(lastMap[Number(b.id)]).getTime() : 0;
      if (aKey !== bKey) {
        return aKey - bKey; // least-recently-used first
      }
      // Secondary: preference score (higher preferred)
      const aPref = prefMap[Number(a.id)] ?? 0;
      const bPref = prefMap[Number(b.id)] ?? 0;
      return bPref - aPref;
    });

    // Tertiary: meal-type distribution balancing (tie-breaker during selection)
    // Track selected meals and tag usage per mealType to promote variety.
    const usedMealsByType: Record<string, Set<string>> = {};
    const tagCountsByType: Record<string, Record<string, number>> = {};

    function ensureTypeState(mealType: string) {
      if (!usedMealsByType[mealType]) usedMealsByType[mealType] = new Set();
      if (!tagCountsByType[mealType]) tagCountsByType[mealType] = {};
    }

    function compareTuples(a: [number, number, number, number], b: [number, number, number, number]) {
      if (a[0] !== b[0]) return a[0] - b[0];            // LRU (earlier last_prepared preferred)
      if (a[1] !== b[1]) return a[1] - b[1];            // Preference (higher better -> we sort by -pref)
      if (a[2] !== b[2]) return a[2] - b[2];            // Distribution penalty (lower better)
      return a[3] - b[3];                               // Stable index
    }

    function getDistributionPenalty(mealType: string, meal: typeof filteredMeals[number]): number {
      // Penalize duplicates within the same mealType across the planning window
      const used = usedMealsByType[mealType] ?? new Set<string>();
      let penalty = used.has(meal.id) ? 1000 : 0; // large penalty to avoid duplicates per mealType
      const counts = tagCountsByType[mealType] ?? {};
      for (const t of meal.tags ?? []) {
        penalty += counts[t] ?? 0; // prefer tags that are less used for this mealType so far
      }
      return penalty;
    }

    function selectBestMealFor(mealType: string): typeof filteredMeals[number] {
      let best: { meal: typeof filteredMeals[number]; tuple: [number, number, number, number] } | null = null;
      for (let i = 0; i < sortedMeals.length; i++) {
        const m = sortedMeals[i];
        const lruKey = lastMap[Number(m.id)] ? new Date(lastMap[Number(m.id)]).getTime() : 0;
        const pref = prefMap[Number(m.id)] ?? 0;
        const penalty = getDistributionPenalty(mealType, m);
        const tuple: [number, number, number, number] = [lruKey, -pref, penalty, i];
        if (!best || compareTuples(tuple, best.tuple) < 0) {
          best = { meal: m, tuple };
        }
      }
      return best ? best.meal : sortedMeals[0];
    }

    for (let dayOffset = 0; dayOffset < days; dayOffset++) {
      const currentDate = new Date(start);
      currentDate.setDate(start.getDate() + dayOffset);
      const dateString = currentDate.toISOString().split('T')[0];

      for (const mealType of mealTypes) {
        // Select best meal honoring LRU -> Preference -> Distribution (tags, duplicates)
        ensureTypeState(mealType);
        const selectedMeal = selectBestMealFor(mealType);
        // Update distribution state
        usedMealsByType[mealType].add(selectedMeal.id);
        for (const t of selectedMeal.tags ?? []) {
          const counts = tagCountsByType[mealType];
          counts[t] = (counts[t] ?? 0) + 1;
        }

        const mealWithHistory = { ...selectedMeal, last_prepared: lastMap[Number(selectedMeal.id)] ?? null };

        suggestions.push({
          date: dateString,
          mealType,
          meal: mealWithHistory,
          reason: dietaryTypes.length > 0 
            ? `Matches your ${dietaryTypes.join(', ')} preferences`
            : 'Recommended based on variety'
        });
      }
    }

    return new Response(JSON.stringify(suggestions), {
      headers: { ...corsHeaders, 'Content-Type': 'application/json' },
      status: 200,
    });
  } catch (error) {
    return new Response(JSON.stringify({ error: error.message }), {
      headers: { ...corsHeaders, 'Content-Type': 'application/json' },
      status: 500,
    });
  }
});
